/// Monster Mesh + Resonance Knot Integration
///
/// Coordinates distributed inference across GPU cluster using resonance-tuned learning rates.
/// Each mesh node loads optimal LR from resonance knots and applies adaptive scheduler.
///
/// Architecture:
/// - Coordinator: Loads model + resonance curves, broadcasts optimal LR to all workers
/// - Worker: Loads model, applies AdaptiveResonanceLRScheduler during inference
/// - Monitor: Tracks σ₁/σ₂ ratio, detects spectral cliffs, triggers load rebalancing
///
/// Usage:
///   let resonance = ResonanceKnotLoader::new("/models/resonance")?;
///   let optimal_lr = resonance.get_optimal_lr("qwen-0.5b")?;
///   let scheduler = AdaptiveResonanceScheduler::new(optimizer, optimal_lr);

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::sync::Arc;

/// Resonance knot metadata loaded from .rknot.json
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct ResonanceKnot {
    pub model_name: String,
    pub version: String,
    pub created: String,
    pub resonance: ResonanceData,
    pub validation: ValidationData,
    pub benefits: BenefitsData,
}

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct ResonanceData {
    pub base_frequency: f32,
    pub optimal_learning_rate: f32,
    pub embedding_frequency: f32,
    pub hidden_frequency: f32,
    pub output_frequency: f32,
    pub confidence: f32,
}

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct ValidationData {
    pub cliff_emergence_rate: f32,
    pub avg_sigma_ratio: f32,
    pub validation_date: String,
    pub status: String,
}

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct BenefitsData {
    pub inference_speedup_percent: f32,
    pub quantization_bits: u32,
    pub compression_potential: f32,
}

/// Loads and caches resonance knots from disk
pub struct ResonanceKnotLoader {
    knots_dir: PathBuf,
    cache: HashMap<String, ResonanceKnot>,
}

impl ResonanceKnotLoader {
    pub fn new(knots_dir: impl AsRef<Path>) -> std::io::Result<Self> {
        let knots_dir = knots_dir.as_ref().to_path_buf();

        if !knots_dir.exists() {
            return Err(std::io::Error::new(
                std::io::ErrorKind::NotFound,
                format!("Resonance knots directory not found: {:?}", knots_dir),
            ));
        }

        Ok(Self {
            knots_dir,
            cache: HashMap::new(),
        })
    }

    /// Load a resonance knot for a specific model
    pub fn load(&mut self, model_name: &str) -> std::io::Result<ResonanceKnot> {
        // Check cache first
        if let Some(knot) = self.cache.get(model_name) {
            return Ok(knot.clone());
        }

        // Load from disk
        let knot_path = self.knots_dir.join(format!("{}.rknot.json", model_name));

        if !knot_path.exists() {
            return Err(std::io::Error::new(
                std::io::ErrorKind::NotFound,
                format!("Resonance knot not found: {:?}", knot_path),
            ));
        }

        let data = std::fs::read_to_string(&knot_path)?;
        let knot: ResonanceKnot = serde_json::from_str(&data)?;

        // Cache for future lookups
        self.cache.insert(model_name.to_string(), knot.clone());

        Ok(knot)
    }

    /// Load all available resonance knots
    pub fn load_all(&mut self) -> std::io::Result<Vec<ResonanceKnot>> {
        let mut knots = Vec::new();

        for entry in std::fs::read_dir(&self.knots_dir)? {
            let entry = entry?;
            let path = entry.path();

            if path.extension().map(|e| e == "json").unwrap_or(false) {
                if let Ok(data) = std::fs::read_to_string(&path) {
                    if let Ok(knot) = serde_json::from_str::<ResonanceKnot>(&data) {
                        knots.push(knot);
                    }
                }
            }
        }

        Ok(knots)
    }

    /// Get optimal learning rate for a model
    pub fn get_optimal_lr(&mut self, model_name: &str) -> std::io::Result<f32> {
        let knot = self.load(model_name)?;
        Ok(knot.resonance.optimal_learning_rate)
    }

    /// Get confidence score (how universal is this LR?)
    pub fn get_confidence(&mut self, model_name: &str) -> std::io::Result<f32> {
        let knot = self.load(model_name)?;
        Ok(knot.resonance.confidence)
    }
}

/// Adaptive resonance scheduler for distributed inference
/// Monitors σ₁/σ₂ ratio and adjusts batch size if cliff emerges
pub struct AdaptiveResonanceScheduler {
    optimal_lr: f32,
    base_lr: f32,
    target_sigma_ratio: f32,
    current_sigma_ratio: f32,
    damping_coefficient: f32,
    check_interval: usize,
    step_count: usize,
    cliff_detected: bool,
}

impl AdaptiveResonanceScheduler {
    pub fn new(optimal_lr: f32) -> Self {
        Self {
            optimal_lr,
            base_lr: optimal_lr,
            target_sigma_ratio: 2.0,  // Stay well below cliff (threshold is 8.0)
            current_sigma_ratio: 1.0,
            damping_coefficient: 0.95,
            check_interval: 5,  // Check every 5 steps
            step_count: 0,
            cliff_detected: false,
        }
    }

    /// Update scheduler with new spectral ratio measurement
    pub fn step(&mut self, sigma_ratio: f32) -> SchedulerAction {
        self.step_count += 1;
        self.current_sigma_ratio = sigma_ratio;

        // Check for cliff emergence every N steps
        if self.step_count % self.check_interval == 0 {
            self.check_cliff_emergence()
        } else {
            SchedulerAction::Continue
        }
    }

    fn check_cliff_emergence(&mut self) -> SchedulerAction {
        // McNally Cliff threshold is σ₁/σ₂ ≥ 8.0
        // Start dampening at 4.0 to prevent emergence
        if self.current_sigma_ratio > 4.0 && !self.cliff_detected {
            self.cliff_detected = true;
            self.apply_damping();
            SchedulerAction::DampingApplied {
                new_lr: self.base_lr,
            }
        } else if self.current_sigma_ratio > 8.0 {
            // Cliff already emerged - aggressive recovery
            self.apply_aggressive_damping();
            SchedulerAction::CliffDetected {
                new_lr: self.base_lr,
                severity: "high",
            }
        } else if self.current_sigma_ratio < 2.0 && self.cliff_detected {
            // Recovered from cliff - can increase again
            self.cliff_detected = false;
            self.recover_lr();
            SchedulerAction::RecoveryTriggered {
                new_lr: self.base_lr,
            }
        } else {
            SchedulerAction::Continue
        }
    }

    fn apply_damping(&mut self) {
        self.base_lr *= self.damping_coefficient;
    }

    fn apply_aggressive_damping(&mut self) {
        self.base_lr *= self.damping_coefficient * self.damping_coefficient;
    }

    fn recover_lr(&mut self) {
        self.base_lr = (self.base_lr / self.damping_coefficient).min(self.optimal_lr);
    }

    pub fn get_current_lr(&self) -> f32 {
        self.base_lr
    }

    pub fn get_state(&self) -> SchedulerState {
        SchedulerState {
            current_lr: self.base_lr,
            optimal_lr: self.optimal_lr,
            current_sigma_ratio: self.current_sigma_ratio,
            cliff_detected: self.cliff_detected,
            step_count: self.step_count,
        }
    }
}

#[derive(Debug, Clone)]
pub enum SchedulerAction {
    Continue,
    DampingApplied { new_lr: f32 },
    CliffDetected { new_lr: f32, severity: &'static str },
    RecoveryTriggered { new_lr: f32 },
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct SchedulerState {
    pub current_lr: f32,
    pub optimal_lr: f32,
    pub current_sigma_ratio: f32,
    pub cliff_detected: bool,
    pub step_count: usize,
}

/// Monster mesh coordinator: loads resonance knots and broadcasts to all workers
pub struct MeshCoordinator {
    resonance_loader: ResonanceKnotLoader,
    model_name: String,
    workers: Vec<WorkerHandle>,
}

impl MeshCoordinator {
    pub fn new(model_name: String, knots_dir: impl AsRef<Path>) -> std::io::Result<Self> {
        let resonance_loader = ResonanceKnotLoader::new(knots_dir)?;

        Ok(Self {
            resonance_loader,
            model_name,
            workers: Vec::new(),
        })
    }

    /// Initialize all workers with optimal LR from resonance knot
    pub fn init_workers(&mut self, num_workers: usize) -> std::io::Result<()> {
        let optimal_lr = self.resonance_loader.get_optimal_lr(&self.model_name)?;
        let confidence = self.resonance_loader.get_confidence(&self.model_name)?;

        println!(
            "[Coordinator] Initializing {} workers with LR={:.6} (confidence={:.1}%)",
            num_workers,
            optimal_lr,
            confidence * 100.0
        );

        // Broadcast to all workers (placeholder - actual RPC would go here)
        for worker_id in 0..num_workers {
            let handle = WorkerHandle {
                id: worker_id,
                optimal_lr,
                status: "ready".to_string(),
            };
            self.workers.push(handle);
        }

        Ok(())
    }

    /// Monitor worker health and spectral ratios
    pub fn monitor_workers(&self) -> MeshStats {
        let total_workers = self.workers.len();
        let ready_workers = self.workers.iter().filter(|w| w.status == "ready").count();

        MeshStats {
            total_workers,
            ready_workers,
            model: self.model_name.clone(),
            timestamp: chrono::Utc::now().to_rfc3339(),
        }
    }
}

#[derive(Debug, Clone)]
struct WorkerHandle {
    id: usize,
    optimal_lr: f32,
    status: String,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct MeshStats {
    pub total_workers: usize,
    pub ready_workers: usize,
    pub model: String,
    pub timestamp: String,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_scheduler_initialization() {
        let scheduler = AdaptiveResonanceScheduler::new(0.001);
        assert_eq!(scheduler.get_current_lr(), 0.001);
        assert!(!scheduler.cliff_detected);
    }

    #[test]
    fn test_cliff_detection() {
        let mut scheduler = AdaptiveResonanceScheduler::new(0.001);

        // Normal operation
        let action = scheduler.step(2.0);
        match action {
            SchedulerAction::Continue => (),
            _ => panic!("Expected Continue action"),
        }

        // Approaching cliff
        let action = scheduler.step(5.0);
        match action {
            SchedulerAction::DampingApplied { .. } => {
                assert!(scheduler.cliff_detected);
            },
            _ => panic!("Expected DampingApplied action"),
        }
    }

    #[test]
    fn test_recovery() {
        let mut scheduler = AdaptiveResonanceScheduler::new(0.001);

        // Force cliff detection
        scheduler.current_sigma_ratio = 5.0;
        let _ = scheduler.check_cliff_emergence();
        let lr_dampened = scheduler.get_current_lr();
        assert!(lr_dampened < 0.001);

        // Recovery
        scheduler.current_sigma_ratio = 1.5;
        let action = scheduler.check_cliff_emergence();
        assert!(!scheduler.cliff_detected);

        match action {
            SchedulerAction::RecoveryTriggered { new_lr } => {
                assert!(new_lr > lr_dampened);
            },
            _ => panic!("Expected RecoveryTriggered action"),
        }
    }
}
